// Butt hinge — two flat leaves, three interlocking knuckles, continuous pin.
// Laid flat (open 180°). Pin axis along Y, leaves on the XY plane.
//
// Dimensions:
//   Leaf:   30 (X, from knuckle out) × 60 (Y) × 3 (Z thickness).
//   Knuckle: 8 mm OD, centered on Y axis at z = 4 (so bottom touches z=0).
//   Pin:    4 mm OD, runs through all knuckles + 1 mm cap each end.
//   Leaves are centered vertically at z = 4 (matching pin axis), so leaf
//     bottom = 2.5, top = 5.5. The knuckle OD (8) extends from z=0 to z=8,
//     so it cleanly engulfs the leaf edge and fuses (≥ 0.5 mm overlap).
//
// Leaves alternate ownership of knuckles:
//   - Leaf A (+X side): owns the middle 20 mm knuckle (Y ∈ [-10, 10]).
//   - Leaf B (−X side): owns the two outer 15 mm knuckles (Y ∈ [-30,-15] and [15,30]).
//
// Each leaf has two countersunk screw holes (3 mm dia, 0.5 mm top chamfer).

const { BREP } = api;

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------
const LEAF_W      = 30;   // X span (knuckle-meet → outer edge)
const LEAF_L      = 60;   // Y length
const LEAF_T      = 3;    // Z thickness
const KNUCKLE_R   = 4;    // outer radius (8 mm diameter)
const PIN_R       = 2;    // pin radius (4 mm diameter)
const PIN_CAP     = 1;    // pin overhang past the knuckle row on each end

const PIN_Z       = KNUCKLE_R;             // pin axis height (= 4)
const LEAF_BOT    = PIN_Z - LEAF_T / 2;    // 2.5
const LEAF_TOP    = PIN_Z + LEAF_T / 2;    // 5.5

const SCREW_R     = 1.5;   // 3 mm screw clearance
const SCREW_CSK   = 0.5;   // countersink chamfer
const LEAF_FILLET = 1.5;   // outer-corner radius

// Knuckle ranges along Y. Outer 15 mm each, middle 20 mm.
const Y_OUT_L_MIN = -30, Y_OUT_L_MAX = -15;
const Y_MID_MIN   = -10, Y_MID_MAX   =  10;
const Y_OUT_R_MIN =  15, Y_OUT_R_MAX =  30;

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

// A knuckle is a cylinder along Y, so build a Z-axis cylinder and rotate.
// BREP.cylinder(r, h) is Z-up with base at z=0. We want length along Y,
// centered at the pin axis (x=0, z=PIN_Z).
function knuckle(yMin, yMax) {
  const len = yMax - yMin;
  // Cylinder along +Z, length `len`. Rotate so its axis points +Y.
  // Rotate -90° about X swings +Z → +Y. After rotation: base was at z=0,
  // now sits at y=0; top (z=len) ends up at y=-len.
  // Easier: build along +Z then rotate about X by 90° to send +Z → -Y? Let's
  // just translate the rotated cylinder into place.
  let c = BREP.cylinder(KNUCKLE_R, len).rotate(-90, [1, 0, 0]);
  // After rotate(-90, X):  +Z → +Y. So a cylinder that spanned z∈[0,len]
  // now spans y∈[0,len], centered on x=0, z=0.
  // Translate so y∈[yMin,yMax] and centerline at z=PIN_Z.
  return c.translate([0, yMin, PIN_Z]);
}

// A leaf body: a slab on one side of the knuckle row, butted up to x=0 so
// the knuckle (radius KNUCKLE_R) sinks ≥ KNUCKLE_R into the leaf, giving
// plenty of volumetric overlap (≫ 0.5 mm).
//
// xSign = +1 for Leaf A (+X side, x ∈ [0, LEAF_W]),
// xSign = -1 for Leaf B (−X side, x ∈ [-LEAF_W, 0]).
function leafSlab(xSign) {
  // BREP.box centers at origin.
  const slab = BREP.box([LEAF_W, LEAF_L, LEAF_T])
    .translate([xSign * LEAF_W / 2, 0, PIN_Z]);
  return slab;
}

// Screw hole: a cylinder running through the leaf thickness, slightly
// taller than the leaf so the cut is clean on both faces.
function screwHole(x, y) {
  const overshoot = 0.5;
  return BREP.cylinder(SCREW_R, LEAF_T + 2 * overshoot)
    .translate([x, y, LEAF_BOT - overshoot]);
}

// ---------------------------------------------------------------------------
// Build Leaf A (+X side): slab + middle knuckle, then fillet outer corners,
// then cut screw holes, then chamfer the top of each hole.
//
// Order matters: fillet BEFORE the cuts (per replicad.md), but the corners
// we want filleted are the leaf's far/free corners (outer X, both Y ends).
// We use an EdgeFilter with `inDirection: [0,0,1]` to grab only the four
// vertical edges of the leaf box, then further restrict by X/Y so we don't
// touch the knuckle ring or the inner (x=0) edge.
// ---------------------------------------------------------------------------

function buildLeaf(xSign, ownedKnuckles) {
  const slab = leafSlab(xSign);

  // Fuse the slab with the knuckle(s) this leaf owns BEFORE filleting, so
  // the fillet solver sees a clean leaf-and-cylinder topology.
  const fused = BREP.fuseAll([slab, ...ownedKnuckles]);

  // Fillet the two outer vertical corners of the leaf (far-X end, both Y
  // extremes). On the +X leaf those corners are near x = +LEAF_W. We use
  // `inDirection: [0,0,1]` to pick only the vertical edges, plus a min/maxX
  // bound to exclude the inner (knuckle) edges. The corners we want are at
  // x = ±LEAF_W (outer), so:
  const outerX = xSign * LEAF_W;
  const filleted = (xSign > 0)
    ? fused.fillet(LEAF_FILLET, {
        inDirection: [0, 0, 1],
        minX: outerX - 0.5,      // only the far-edge corners
      })
    : fused.fillet(LEAF_FILLET, {
        inDirection: [0, 0, 1],
        maxX: outerX + 0.5,
      });

  // Two screw holes per leaf: spaced along Y at roughly ±20 mm, and at the
  // outer-X half (so they don't collide with the knuckle).
  const xHole = xSign * (LEAF_W * 0.65);    // 65% of the way out
  const holes = [
    screwHole(xHole, -20),
    screwHole(xHole,  20),
  ];
  const drilled = BREP.cutAll([filleted, ...holes]);

  // Chamfer the TOP rim of each screw hole (countersink). The top face of
  // the leaf is at z = LEAF_TOP (5.5). The hole-top edges are circles lying
  // in the XY plane at z = LEAF_TOP. Filter by `maxZ` just below the top
  // (so we miss the bottom rim, but catch the top circles).
  //
  // NB: this also catches any other edges that sit just below z=LEAF_TOP,
  // but in practice the only horizontal edges in that band are the hole
  // top circles + the slab's top rectangle. We restrict to the top face
  // by also using `parallelToPlane: 'XY'` (catches both, fine) and
  // `nearPoint`+`withinDist` would be ideal but we'd need two filters.
  //
  // Simpler: chamfer all edges in a thin Z band at LEAF_TOP that are NOT
  // the slab's outer rectangle. We can do that by `withinDist` from each
  // hole center.
  const chamfered = drilled
    .chamfer(SCREW_CSK, {
      nearPoint: [xHole, -20, LEAF_TOP],
      withinDist: SCREW_R + 0.2,
    })
    .chamfer(SCREW_CSK, {
      nearPoint: [xHole,  20, LEAF_TOP],
      withinDist: SCREW_R + 0.2,
    });

  return chamfered;
}

// ---------------------------------------------------------------------------
// Build all knuckles and assign ownership.
// ---------------------------------------------------------------------------

const knuckleMid    = knuckle(Y_MID_MIN,   Y_MID_MAX);    // Leaf A owns
const knuckleOuterL = knuckle(Y_OUT_L_MIN, Y_OUT_L_MAX);  // Leaf B owns
const knuckleOuterR = knuckle(Y_OUT_R_MIN, Y_OUT_R_MAX);  // Leaf B owns

const leafA = buildLeaf(+1, [knuckleMid]);
const leafB = buildLeaf(-1, [knuckleOuterL, knuckleOuterR]);

// ---------------------------------------------------------------------------
// Pin: runs through all knuckles plus 1 mm cap each end.
// Total pin length = (Y_OUT_R_MAX - Y_OUT_L_MIN) + 2*PIN_CAP = 60 + 2 = 62.
// ---------------------------------------------------------------------------
const pinLen = (Y_OUT_R_MAX - Y_OUT_L_MIN) + 2 * PIN_CAP;
const pin = BREP.cylinder(PIN_R, pinLen)
  .rotate(-90, [1, 0, 0])
  .translate([0, Y_OUT_L_MIN - PIN_CAP, PIN_Z]);

// ---------------------------------------------------------------------------
// Return the assembly. We keep the pin as a separate component (intentional
// for a real hinge) by fuseAll'ing leafA + leafB into the hinge body and
// then composing with the pin via fuseAll. The two leaves are interlocked
// (alternating knuckles), so they don't fuse into one solid — that's
// expected and gives componentCount = 2 (leaves+pin overlapping but the
// leaves' bodies remain separate at the knuckle row gaps).
// ---------------------------------------------------------------------------

return BREP.fuseAll([leafA, leafB, pin]);
